import{_ as t,o,c as n,ag as a}from"./chunks/framework.CpPsmr6h.js";const p=JSON.parse('{"title":"TCP for Beginners","description":"","frontmatter":{},"headers":[],"relativePath":"docs/tcp.md","filePath":"docs/tcp.md","lastUpdated":1771868171000}'),i={name:"docs/tcp.md"};function l(s,e,r,c,d,u){return o(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="tcp-for-beginners" tabindex="-1">TCP for Beginners <a class="header-anchor" href="#tcp-for-beginners" aria-label="Permalink to &quot;TCP for Beginners&quot;">​</a></h1><p>TCP (Transmission Control Protocol) is a low-level network protocol used by many applications that need reliable data delivery. Unlike HTTP, TCP is not tied to web semantics like URLs or methods; it just provides a reliable byte stream between two endpoints.</p><h2 id="quick-mental-model" tabindex="-1">Quick Mental Model <a class="header-anchor" href="#quick-mental-model" aria-label="Permalink to &quot;Quick Mental Model&quot;">​</a></h2><ul><li>TCP creates a connection between a client and a server.</li><li>Data is delivered in order.</li><li>Lost packets are retransmitted automatically.</li><li>The connection stays open until one side closes it.</li></ul><h2 id="where-tcp-is-used" tabindex="-1">Where TCP Is Used <a class="header-anchor" href="#where-tcp-is-used" aria-label="Permalink to &quot;Where TCP Is Used&quot;">​</a></h2><ul><li>Databases (for example, PostgreSQL and MySQL).</li><li>SSH connections.</li><li>Many custom backend protocols.</li><li>Some game and IoT services.</li></ul><h2 id="tcp-vs-http-beginner-view" tabindex="-1">TCP vs HTTP (Beginner View) <a class="header-anchor" href="#tcp-vs-http-beginner-view" aria-label="Permalink to &quot;TCP vs HTTP (Beginner View)&quot;">​</a></h2><ul><li>TCP: Transport layer protocol (moves bytes reliably).</li><li>HTTP: Application protocol (defines request/response rules) that usually runs on top of TCP.</li></ul><h2 id="ports-and-endpoints" tabindex="-1">Ports and Endpoints <a class="header-anchor" href="#ports-and-endpoints" aria-label="Permalink to &quot;Ports and Endpoints&quot;">​</a></h2><ul><li>A service listens on a TCP port (for example, <code>5432</code> for PostgreSQL).</li><li>Clients connect to <code>host:port</code>.</li><li>If the port is not reachable, the connection fails.</li></ul><h2 id="when-to-use-tcp-tunneling" tabindex="-1">When to Use TCP Tunneling <a class="header-anchor" href="#when-to-use-tcp-tunneling" aria-label="Permalink to &quot;When to Use TCP Tunneling&quot;">​</a></h2><ul><li>You need secure remote access to non-HTTP services.</li><li>You are exposing internal tools that use raw TCP protocols.</li><li>You need stable, long-lived connections.</li></ul><h2 id="how-this-works-in-tunnelbox" tabindex="-1">How This Works in TunnelBox <a class="header-anchor" href="#how-this-works-in-tunnelbox" aria-label="Permalink to &quot;How This Works in TunnelBox&quot;">​</a></h2><p><em>TODO: Add TunnelBox-specific TCP tunnel setup, security model, and operational limits.</em></p>',14)])])}const T=t(i,[["render",l]]);export{p as __pageData,T as default};
